import { ref } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'

export function useProfileData() {
  const loading = ref(false)
  const basicInfo = ref(null)
  const profileData = ref({
    basic_info: null,
    job_intention: null,
    work_experience: null,
    education: null,
    project: null,
    skill: null,
    certificate: null,
    language: null,
    portfolio: null,
    social_link: null
  })
  const completionData = ref({
    total_score: 0,
    dimensions: {},
    suggestions: []
  })

  // 获取基本信息
  const fetchBasicInfo = async () => {
    try {
      loading.value = true
      const response = await profile.getBasicInfo()
      console.log('基本信息响应:', response.data)

      if (response.data?.code === 200) {
        const { user, basic_info } = response.data.data

        // 合并用户信息和基本信息
        basicInfo.value = {
          ...user,
          ...basic_info,
          avatar: basic_info?.avatar || user?.avatar
        }

        profileData.value.basic_info = basicInfo.value
        return basicInfo.value
      }
      return null
    } catch (error) {
      console.error('获取基本信息失败:', error)
      return null
    } finally {
      loading.value = false
    }
  }

  // 获取模块数据
  const fetchModuleData = async (moduleType) => {
    try {
      loading.value = true
      let response

      switch (moduleType) {
        case 'job_intention':
          response = await profile.jobIntention.get()
          break
        case 'work_experience':
          response = await profile.workExperience.list()
          break
        case 'education':
          response = await profile.education.list()
          break
        // ... 其他模块的数据获取
      }

      if (response?.data?.code === 200) {
        profileData.value[moduleType] = response.data.data
        return response.data.data
      }
      return null
    } catch (error) {
      console.error(`获取${moduleType}数据失败:`, error)
      return null
    } finally {
      loading.value = false
    }
  }

  // 获取简历完整度数据
  const fetchCompletionData = async () => {
    try {
      const response = await profile.getCompleteness()
      console.log('完整度数据响应:', response.data)

      if (response.data?.code === 200) {
        completionData.value = response.data.data
        return response.data.data
      }
      return null
    } catch (error) {
      console.error('获取完整度数据失败:', error)
      return null
    }
  }

  return {
    loading,
    basicInfo,
    profileData,
    completionData,
    fetchBasicInfo,
    fetchModuleData,
    fetchCompletionData
  }
}
